Usage: $0 [options]

Options:
  -k --kilometers  Output distance in kilometers
  -m --miles      Output distance in miles
  -h --help       Show this help message

Example:
  $0 -k 40.7128  -l -74.0060  -h  -m 41.8781  -l  -73.9352
EOF;

# Parse command-line options
my ($lat1, $lon1, $lat2, $lon2);
my ($km, $mi) = (0, 0);

GetOptions(
    'k' => \$km,
    'm' => \$mi,
    'h' => \&help,
    'lat1=s' => \$lat1,
    'lon1=s' => \$lon1,
    'lat2=s' => \$lat2,
    'lon2=s' => \$lon2,
) or die $help;

# Validate inputs
if (!defined $lat1 || !defined $lon1 || !defined $lat2 || !defined $lon2) {
    die "Please provide latitude and longitude for both locations.\n";
}

# Validate latitude and longitude ranges
unless ( -d $lat1 && -d $lon1 && -d $lat2 && -d $lon2 ) {
    die "Invalid latitude or longitude values. Latitude must be between -90 and 90, and longitude between -180 and 180.\n";
}

# Function to convert degrees to radians
sub deg2rad {
    return (2 * pi) / 360 * $_[0];
}

# Haversine formula
sub haversine {
    my ($lat1, $lon1, $lat2, $lon2) = @_;
    my $R = 6371; # Radius of Earth in kilometers

    my $dlat = deg2rad($lat2 - $lat1);
    my $dlon = deg2rad($lon2 - $lon1);

    my $a = (sin($dlat/2) ** 2) + cos(deg2rad($lat1)) * cos(deg2rad($lat2)) * (sin($dlon/2) ** 2);
    my $c = 2 * atan2(sqrt($a), sqrt(1 - $a));
    my $distance = $R * $c;

    return $distance;
}

# Calculate distance
